const MONTHS=["Janeiro","Fevereiro","Março","Abril","Maio","Junho","Julho","Agosto","Setembro","Outubro","Novembro","Dezembro"];
const START_YM="2026-01";
function ci(ym){const[y,m]=ym.split("-");return (+y)*12+(+m);}
function ymOf(d){return d.getFullYear()+"-"+String(d.getMonth()+1).padStart(2,"0");}
const CUR_YM=ymOf(new Date());
function buildComps(){const out=[];let a=ci(START_YM),b=ci(CUR_YM<START_YM?START_YM:CUR_YM);for(let x=a;x<=b;x++){const y=Math.floor((x-1)/12),m=((x-1)%12)+1;out.push(y+"-"+String(m).padStart(2,"0"));}return out;}
const COMPS=buildComps();
const compLabel=(ym)=>{const[y,m]=ym.split("-");return MONTHS[+m-1]+"/"+y;};
function isActiveIn(c,ym){ if(c.situacao==="Ativo") return true; if(!c.dataSituacao) return false; return ci(ym)<ci(c.dataSituacao.slice(0,7)); }
function fmtDT(ts){const d=new Date(ts);const p=n=>String(n).padStart(2,"0");return p(d.getDate())+"/"+p(d.getMonth()+1)+"/"+d.getFullYear()+" "+p(d.getHours())+":"+p(d.getMinutes());}

const SN=["Sim","Não"];
const OBRIG=[["EFD ICMS/IPI","efdicms"],["EFD Contribuições","efdcontrib"],["PGDAS","pgdas"],["DeSTDA","destda"],["EFD REINF","efdreinf"],["MIT","mit"],["DIRBI","dirbi"],["DCTF-Web","dctfweb"]];
const OBRIG_ST=["Pendente","Entregue","N/A","Não obrigada"];
const PROC=["holerites","vrCesta","alocRPA","fgts","darfDae","dcomp"];
const OTHER_DEPTS=["contabil","paralegal","financeiro","recepcao","rh"];
const DEPT_LABEL={central:"Cadastro Central",fiscal:"Fiscal",pessoal:"Pessoal",contabil:"Contábil",paralegal:"Paralegal",financeiro:"Financeiro",recepcao:"Recepção",rh:"RH Interno"};

function defaultPD(c){
  const obrig={}; OBRIG.forEach(([,k])=>obrig[k]={obrig:"Pendente",data:"",ret:""});
  const semFolha=(c.tipoFolha==="SEM FOLHA");
  const pf={tipoFolha:c.tipoFolha||"SEM FOLHA",distLucroPess:"",sindicatos:"",dissidio:"",obsFolha:""};
  PROC.forEach(k=>pf[k]=semFolha?"—":"Pendente");
  pf.retificacao="Não"; pf.pessoalConcluido=semFolha?"—":"Não"; pf.pessoalData=""; pf.confEnvio="Não"; pf.modalidade=""; pf.protocolo="";
  return {semMovimento:false,_meta:null,
    fiscal:{fat:"",distLucro:"",fatorR:"Não",concomitante:"Não",obrigTEF:"Não",stAntecip:"Não",beneficioFiscal:"",entradas:"",saidas:"",servPrest:"",servTom:"",cteEmit:"",cteTom:"",nfce:"",pis:"",cofins:"",csll:"",irpj:"",issqn:"",simples:"",icms:"",icmsDifal:"",irrf:"",crf:"",inssRet:"",senar:"",funrural:"",fethab:"",iagro:"",fiscalConcluido:"Não",fiscalDataConcl:"",formaEnvio:"",dataEnvio:"",fiscalConfirmacao:"Não",pdfCreditos:"",obrig,coordFiscal:{fin:"Não",data:"",obs:""},depContabil:{fin:"Não",data:"",obs:""}},
    pessoal:pf};
}
function mergePD(st,c){const d=defaultPD(c); if(!st) return d; return {semMovimento:st.semMovimento??d.semMovimento,_meta:st._meta||null,fiscal:{...d.fiscal,...(st.fiscal||{}),obrig:{...d.fiscal.obrig,...((st.fiscal||{}).obrig||{})},coordFiscal:{...d.fiscal.coordFiscal,...((st.fiscal||{}).coordFiscal||{})},depContabil:{...d.fiscal.depContabil,...((st.fiscal||{}).depContabil||{})}},pessoal:{...d.pessoal,...(st.pessoal||{})}};}

function fiscalExcl(pd){return pd.semMovimento?"S/M":null;}
function pessoalExcl(pd,c){if(pd.semMovimento)return "S/M"; if((pd.pessoal.tipoFolha||c.tipoFolha)==="SEM FOLHA")return "Sem folha"; return null;}
function fiscalNum(pd){ if(pd.semMovimento) return 100; const fx=pd.fiscal; let dn=0; const TOT=OBRIG.length+2;
  OBRIG.forEach(([,k])=>{const v=fx.obrig[k].obrig; if(v==="Entregue"||v==="N/A"||v==="Não obrigada") dn++;}); if(fx.fiscalConcluido==="Sim") dn++; if(fx.fiscalConfirmacao==="Sim") dn++; return Math.round(dn/TOT*100); }
function pessoalNum(pd,c){ if(pessoalExcl(pd,c)) return 100; const pf=pd.pessoal; let dn=0; const TOT=PROC.length+2; PROC.forEach(k=>{if(pf[k]==="Concluído") dn++;}); if(pf.pessoalConcluido==="Sim") dn++; if(pf.confEnvio==="Sim") dn++; return Math.round(dn/TOT*100); }

function sortBy(list,sort){const{key,dir}=sort;const a=[...list];a.sort((x,y)=>{ if(key==="codigo"){return ((+x.codigo||0)-(+y.codigo||0))*dir;} if(key==="cnpj"){const u=(x.cnpj||"").replace(/\D/g,""),v=(y.cnpj||"").replace(/\D/g,"");return (u<v?-1:u>v?1:0)*dir;} const u=(x.razao||"").toUpperCase(),v=(y.razao||"").toUpperCase();return (u<v?-1:u>v?1:0)*dir;});return a;}

function Pill({children,bg,fg,br}){return <span style={{fontSize:11,fontWeight:600,padding:"3px 9px",borderRadius:6,background:bg,color:fg,border:`1px solid ${br||"transparent"}`,whiteSpace:"nowrap"}}>{children}</span>;}
const STMAP={"Concluído":[C.greenSoft,C.green,"#cfe3d6"],"Em andamento":[C.amberSoft,C.amber,"#ecdcb6"],"Pendente":[C.bg,C.muted,C.line],"Ativo":[C.greenSoft,C.green,"#cfe3d6"],"Inativo":[C.bg,C.muted,C.line],"Bloqueada":[C.redSoft,C.red,"#e7c8bf"],"Sim":[C.greenSoft,C.green,"#cfe3d6"],"Não":[C.bg,C.muted,C.line],"Entregue":[C.greenSoft,C.green,"#cfe3d6"],"N/A":[C.bg,C.muted,C.line],"Não obrigada":[C.bg,C.muted,C.line],"S/M":[C.navySoft,C.navy,"#dbe2f0"],"—":[C.bg,C.muted,C.line]};
function StatusPill({s}){const m=STMAP[s]||STMAP["—"];return <Pill bg={m[0]} fg={m[1]} br={m[2]}>{s}</Pill>;}
function barColor(p){return p>=100?C.green:p>=50?C.amber:p>0?C.navy:C.muted;}
function Bar({pct,w}){return <div style={{height:6,width:w||"100%",borderRadius:4,background:C.line,overflow:"hidden"}}><div style={{width:Math.max(0,Math.min(100,pct))+"%",height:"100%",background:barColor(pct),borderRadius:4,transition:"width .3s"}}/></div>;}
function RowProg({excl,prog}){ if(excl) return <Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">{excl}</Pill>;
  return <div style={{display:"flex",alignItems:"center",gap:8,minWidth:96}}><Bar pct={prog} w={56} /><span className="tnum" style={{fontSize:12,fontWeight:800,color:barColor(prog)}}>{prog}%</span></div>; }

const DEPTS=[{key:"central",label:"Cadastro Central",icon:Building2,hint:"Fonte única"},{key:"fiscal",label:"Fiscal",icon:Receipt},{key:"pessoal",label:"Pessoal",icon:Users},{key:"contabil",label:"Contábil",icon:BookOpen},{key:"paralegal",label:"Paralegal",icon:Scale},{key:"financeiro",label:"Financeiro",icon:Wallet},{key:"recepcao",label:"Recepção",icon:Phone},{key:"rh",label:"RH Interno",icon:UserCog}];
const money=(n)=>(typeof n==="number"?n:Number(n)||0).toLocaleString("pt-BR",{style:"currency",currency:"BRL"});
const FISCAL_FORM=[{sec:"Observações importantes",rows:[{k:"fat",l:"Faturamento Mensal",t:"money"},{k:"distLucro",l:"Distribuição de Lucro",t:"text"},{k:"fatorR",l:"Fator R",t:"sel",o:SN},{k:"concomitante",l:"Concomitante",t:"sel",o:SN},{k:"obrigTEF",l:"Obrigat. TEF",t:"sel",o:SN},{k:"stAntecip",l:"Recolh. ST Antecip.",t:"sel",o:SN},{k:"beneficioFiscal",l:"Benefício Fiscal",t:"text"}]},
{sec:"Escrituração",rows:[{k:"entradas",l:"Entradas",t:"money"},{k:"saidas",l:"Saídas",t:"money"},{k:"servPrest",l:"Serv. Prestados",t:"money"},{k:"servTom",l:"Serv. Tomados",t:"money"},{k:"cteEmit",l:"CT-e Emit.",t:"money"},{k:"cteTom",l:"CT-e Tom.",t:"money"},{k:"nfce",l:"NFC-e",t:"money"}]},
{sec:"Impostos",rows:[{k:"pis",l:"PIS",t:"money"},{k:"cofins",l:"COFINS",t:"money"},{k:"csll",l:"CSLL",t:"money"},{k:"irpj",l:"IRPJ",t:"money"},{k:"issqn",l:"ISSQN",t:"money"},{k:"simples",l:"Simples N.",t:"money"},{k:"icms",l:"ICMS Mensal",t:"money"},{k:"icmsDifal",l:"ICMS Difal",t:"money"}]},
{sec:"Retenções",rows:[{k:"irrf",l:"IRRF",t:"money"},{k:"crf",l:"CRF",t:"money"},{k:"inssRet",l:"INSS Ret.",t:"money"},{k:"senar",l:"SENAR",t:"money"},{k:"funrural",l:"FUNRURAL",t:"money"},{k:"fethab",l:"FETHAB",t:"money"},{k:"iagro",l:"IAGRO",t:"money"}]},
{sec:"Encerramento fiscal",rows:[{k:"fiscalConcluido",l:"Concluído",t:"sel",o:SN},{k:"fiscalDataConcl",l:"Data de conclusão",t:"date"},{k:"formaEnvio",l:"Forma de envio",t:"text"},{k:"dataEnvio",l:"Data de envio",t:"date"},{k:"fiscalConfirmacao",l:"Confirmação",t:"sel",o:SN},{k:"pdfCreditos",l:"PDF - Créditos",t:"text"}]}];
const PESSOAL_FORM=[{sec:"Folha",rows:[{k:"tipoFolha",l:"Tipo de Folha",t:"sel",o:["LANÇAMENTO","FOLHA","PRÓ-LABORE","PROLABORE","SEM FOLHA","INATIVA"]},{k:"distLucroPess",l:"Dist. Lucro",t:"text"},{k:"sindicatos",l:"Sindicatos",t:"text"},{k:"dissidio",l:"Dissídio",t:"text"},{k:"obsFolha",l:"Observações p/ Folha",t:"text"}]},
{sec:"Processamento",rows:[{k:"holerites",l:"Holerites",t:"status"},{k:"vrCesta",l:"VR/Cesta/Gás",t:"status"},{k:"alocRPA",l:"Aloc. RPA",t:"status"},{k:"fgts",l:"FGTS",t:"status"},{k:"darfDae",l:"DARF/DAE",t:"status"},{k:"dcomp",l:"DCOMP",t:"status"},{k:"retificacao",l:"Retificação",t:"sel",o:SN}]},
{sec:"Encerramento",rows:[{k:"pessoalConcluido",l:"Concluído",t:"sel",o:SN},{k:"pessoalData",l:"Data",t:"date"},{k:"confEnvio",l:"Confirmação de Envio",t:"sel",o:SN},{k:"modalidade",l:"Modalidade de Envio",t:"text"},{k:"protocolo",l:"N° Protocolo/E-mail",t:"text"}]}];
const STAT_OPTS=["Pendente","Em andamento","Concluído"];
const deptEmps=(emps,d)=>emps.filter(e=>e.ativo&&e.dept===d).map(e=>e.nome);
const FLABEL={}; FISCAL_FORM.forEach(s=>s.rows.forEach(r=>FLABEL[r.k]=r.l));
const PLABEL={}; PESSOAL_FORM.forEach(s=>s.rows.forEach(r=>PLABEL[r.k]=r.l));
const CLABEL={codigo:"Código",razao:"Razão social",cnpj:"CNPJ",regime:"Regime",municipio:"Município",situacao:"Situação",dataSituacao:"Data situação"};
function disp(v){return (v===""||v===undefined||v===null)?"—":String(v);}
function diffPD(o,n,kind){const ch=[]; if((o.semMovimento||false)!==(n.semMovimento||false))ch.push("Sem movimento: "+(o.semMovimento?"Sim":"Não")+" → "+(n.semMovimento?"Sim":"Não"));
  if(kind==="fiscal"){const a=o.fiscal,b=n.fiscal; Object.keys(FLABEL).forEach(k=>{if((a[k]??"")!==(b[k]??""))ch.push(FLABEL[k]+": "+disp(a[k])+" → "+disp(b[k]));}); OBRIG.forEach(([l,k])=>{if(a.obrig[k].obrig!==b.obrig[k].obrig)ch.push(l+": "+a.obrig[k].obrig+" → "+b.obrig[k].obrig); if((a.obrig[k].data||"")!==(b.obrig[k].data||""))ch.push(l+" (data): "+disp(a.obrig[k].data)+" → "+disp(b.obrig[k].data));}); [["coordFiscal","Coord. Fiscal"],["depContabil","Dep. Contábil"]].forEach(([g,lab])=>{if(a[g].fin!==b[g].fin)ch.push(lab+": "+a[g].fin+" → "+b[g].fin);});}
  else{const a=o.pessoal,b=n.pessoal; Object.keys(PLABEL).forEach(k=>{if((a[k]??"")!==(b[k]??""))ch.push(PLABEL[k]+": "+disp(a[k])+" → "+disp(b[k]));});}
  return ch; }

export default function App(){
  const [me,setMe]=useState(null);
  const [db,setDb]=useState(null);
  const [loading,setLoading]=useState(true);
  const [comp,setComp]=useState(CUR_YM<START_YM?START_YM:CUR_YM);
  const [active,setActive]=useState("dashboard");
  const [query,setQuery]=useState("");
  const [f,setF]=useState({regime:"todos",municipio:"todos",situacao:"todos",resp:"todos"});
  const [sort,setSort]=useState({key:"razao",dir:1});
  const [view,setView]=useState("lista");
  const [editId,setEditId]=useState(null);const [draft,setDraft]=useState({});
  const [delId,setDelId]=useState(null);const [adding,setAdding]=useState(false);const [openId,setOpenId]=useState(null);
  const [empEdit,setEmpEdit]=useState(null);
  const [toast,setToast]=useState(null);
  const notify=(m,kind)=>{setToast({m,kind});setTimeout(()=>setToast(null),2600);};

  useEffect(()=>{let alive=true;(async()=>{
    const seed={registry:REGISTRY_SEED,employees:EMP_SEED,periods:{},log:[]};
    if(typeof window==="undefined"||!window.storage){ if(alive){setDb(seed);setLoading(false);} return; }
    try{const r=await window.storage.get(DB_KEY,true); if(alive&&r&&r.value){setDb(JSON.parse(r.value));setLoading(false);return;}}catch(e){}
    if(alive){setDb(seed);setLoading(false); try{await window.storage.set(DB_KEY,JSON.stringify(seed),true);}catch(e){}}
  })();return ()=>{alive=false;};},[]);
  const mutate=(fn,logAction)=>{ setDb(prev=>{ let next=fn(prev); if(logAction){next={...next,log:[...(prev.log||[]),{ts:Date.now(),user:me?me.nome:"—",action:logAction}].slice(-1000)};} if(typeof window!=="undefined"&&window.storage){window.storage.set(DB_KEY,JSON.stringify(next),true).catch(()=>{});} return next; }); };

  const registry=db?db.registry:[];
  const employees=db?db.employees:EMP_SEED;
  const periods=db?db.periods:{};

  const isAdmin=me&&!!me.isAdmin;
  const canManageCentral=me&&(isAdmin||!!me.canCentral);
  const canEditDept=(d)=>me&&(isAdmin||me.deptEdit===d);
  const canView=(d)=>me&&(isAdmin||(me.view||[]).includes(d));
  const canAssignHere=(kind)=>me&&(isAdmin||(me.canAssign&&me.deptEdit===kind));
  const canEditFicha=(c,kind)=>{ if(!me)return false; if(isAdmin)return true; if(me.deptEdit!==kind)return false; if(me.onlyAssigned){const r=kind==="fiscal"?c.respFiscal:c.respPessoal; return r===me.nome;} return true; };

  const getPD=(c)=>mergePD(periods[comp]&&periods[comp][c.id],c);
  const updateReg=(id,patch,log)=>mutate(prev=>({...prev,registry:prev.registry.map(c=>c.id===id?{...c,...patch}:c)}),log);
  const editCell=(c,kind,mutator)=>{const old=mergePD(periods[comp]&&periods[comp][c.id],c);const nx=mutator(JSON.parse(JSON.stringify(old)));nx._meta={by:me.nome,at:Date.now()};const ch=diffPD(old,nx,kind);const logStr=ch.length?`${kind==="fiscal"?"Fiscal":"Pessoal"} · ${c.razao} (${compLabel(comp)}): ${ch.join("; ")}`:null;mutate(prev=>({...prev,periods:{...prev.periods,[comp]:{...(prev.periods[comp]||{}),[c.id]:nx}}}),logStr);};

  const municipios=useMemo(()=>[...new Set(registry.map(c=>c.municipio).filter(Boolean))].sort(),[registry]);
  const inComp=useMemo(()=>registry.filter(c=>isActiveIn(c,comp)),[registry,comp]);
  const respField=active==="fiscal"?"respFiscal":active==="pessoal"?"respPessoal":null;
  const respOpts=active==="fiscal"?deptEmps(employees,"fiscal"):active==="pessoal"?deptEmps(employees,"pessoal"):null;

  const applyFilters=(list)=>{const q=query.trim().toLowerCase();return list.filter(c=>{
    if(q&&!((c.razao||"").toLowerCase().includes(q)||(c.cnpj||"").includes(q)||String(c.codigo).includes(q)))return false;
    if(f.regime!=="todos"&&c.regime!==f.regime)return false;
    if(f.municipio!=="todos"&&c.municipio!==f.municipio)return false;
    if(f.situacao!=="todos"&&c.situacao!==f.situacao)return false;
    if(respField&&f.resp!=="todos"&&c[respField]!==f.resp)return false;
    return true;});};
  const centralList=useMemo(()=>sortBy(applyFilters(registry),sort),[registry,query,f,sort]);
  const deptList=useMemo(()=>sortBy(applyFilters(inComp),sort),[inComp,query,f,active,sort]);

  const statsOf=(kind,list)=>{let sum=0,c100=0,pend=0,applic=0,na=0;const tot=list.length;list.forEach(c=>{const pd=getPD(c);const ex=kind==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c);if(ex){na++;return;}applic++;const v=kind==="fiscal"?fiscalNum(pd):pessoalNum(pd,c);sum+=v;if(v===100)c100++;else pend++;});
    const obrig={};if(kind==="fiscal"){OBRIG.forEach(([,k])=>{let a=0,d=0;list.forEach(c=>{const pd=getPD(c);if(pd.semMovimento)return;const val=pd.fiscal.obrig[k].obrig;if(val==="Pendente"||val==="Entregue"){a++;if(val==="Entregue")d++;}});obrig[k]=a?Math.round(d/a*100):0;});}
    return {avg:applic?Math.round(sum/applic):0,c100,pend,na,applic,tot,obrig};};
  const modStats=useMemo(()=>active==="fiscal"||active==="pessoal"?statsOf(active,deptList):null,[active,deptList,periods,comp]);

  if(!me) return <Login employees={employees} onLogin={(u)=>{setMe(u);setActive("dashboard");}} />;
  if(loading||!db) return <Splash />;
  const opened=registry.find(c=>c.id===openId);
  const navDepts=DEPTS.filter(d=>canView(d.key));
  const allowed=new Set(["dashboard",...navDepts.map(d=>d.key)]); if(isAdmin){allowed.add("equipe");allowed.add("historico");}
  const act=allowed.has(active)?active:"dashboard";
  const meLabel=isAdmin?"Administrador":(me.cargo||"Colaborador");
  const showComp=!["equipe","historico"].includes(act);
  const showFilters=["central","fiscal","pessoal"].includes(act);
  const title={dashboard:"Início",equipe:"Equipe & Acessos",historico:"Histórico de alterações"}[act]||DEPT_LABEL[act];

  const saveFicha=(regPatch,newPD)=>{ const id=opened.id; const razao=opened.razao; const oldPD=mergePD(periods[comp]&&periods[comp][id],opened);
    const ch=diffPD(oldPD,newPD,act); if(regPatch.respFiscal!==undefined)ch.push("Resp. Fiscal → "+(regPatch.respFiscal||"—")); if(regPatch.respPessoal!==undefined)ch.push("Resp. Pessoal → "+(regPatch.respPessoal||"—"));
    const logStr=ch.length?`${act==="fiscal"?"Fiscal":"Pessoal"} · ${razao} (${compLabel(comp)}): ${ch.join("; ")}`:null;
    mutate(prev=>{const reg=Object.keys(regPatch).length?prev.registry.map(c=>c.id===id?{...c,...regPatch}:c):prev.registry; const periods={...prev.periods,[comp]:{...(prev.periods[comp]||{}),[id]:newPD}}; return {...prev,registry:reg,periods};}, logStr);
    notify("Ficha salva.","ok"); setOpenId(null); };

  return (
    <div style={{position:"relative",display:"flex",height:"100vh",minHeight:600,background:C.bg,color:C.ink,overflow:"hidden"}}>
      <style>{FONTS}</style>
      <aside style={{width:236,background:C.card,borderRight:`1px solid ${C.line}`,display:"flex",flexDirection:"column",flexShrink:0}}>
        <div style={{padding:"18px 18px 12px",borderBottom:`1px solid ${C.line}`,display:"flex",alignItems:"center",gap:10}}>
          <img src={LOGO_SYM} alt="" style={{width:30,height:30,objectFit:"contain"}} />
          <div><img src={LOGO_WORD} alt="CONTABILIZARe" style={{height:15,display:"block"}} /><div style={{fontSize:9.5,color:C.muted,letterSpacing:2,marginTop:3}}>HUB INTERNO</div></div>
        </div>
        <nav style={{flex:1,padding:"8px 10px",overflow:"auto"}}>
          <NavItem icon={Home} label="Início" on={act==="dashboard"} onClick={()=>setActive("dashboard")} />
          <div style={{height:1,background:C.line,margin:"8px 6px"}} />
          {navDepts.map(d=>{const home=me.deptEdit===d.key;return <NavItem key={d.key} icon={d.icon} label={d.label} hint={d.hint} dot={home&&!d.hint} on={act===d.key} onClick={()=>{setActive(d.key);setEditId(null);setDelId(null);setF({regime:"todos",municipio:"todos",situacao:"todos",resp:"todos"});}} />;})}
          {isAdmin&&<><div style={{height:1,background:C.line,margin:"8px 6px"}} />
          <NavItem icon={UserPlus} label="Equipe & Acessos" on={act==="equipe"} onClick={()=>setActive("equipe")} />
          <NavItem icon={History} label="Histórico" on={act==="historico"} onClick={()=>setActive("historico")} /></>}
        </nav>
        <div style={{padding:12,borderTop:`1px solid ${C.line}`,display:"flex",alignItems:"center",gap:10}}>
          <div style={{width:32,height:32,borderRadius:8,background:C.navy,color:"#fff",display:"grid",placeItems:"center",fontWeight:700,fontSize:13}}>{me.nome[0]}</div>
          <div style={{flex:1,fontSize:12.5,minWidth:0}}><div style={{fontWeight:700,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{me.nome}</div><div style={{color:C.muted,fontSize:11}}>{meLabel}</div></div>
          <button onClick={()=>setMe(null)} title="Sair" style={{background:"none",border:"none",color:C.muted,cursor:"pointer"}}><LogOut size={16} /></button>
        </div>
      </aside>

      <main style={{flex:1,display:"flex",flexDirection:"column",minWidth:0}}>
        <header style={{display:"flex",alignItems:"center",gap:14,padding:"14px 24px",borderBottom:`1px solid ${C.line}`,background:C.card,flexShrink:0}}>
          <div style={{flex:1,minWidth:0}}><div style={{fontSize:11,color:C.muted,letterSpacing:1.2,textTransform:"uppercase",fontWeight:600}}>{meLabel}</div>
            <h1 style={{margin:"2px 0 0",fontSize:21,fontWeight:800,color:C.ink,letterSpacing:-0.3}}>{title}</h1></div>
          {showComp&&<div style={{display:"flex",alignItems:"center",gap:7,padding:"7px 11px",borderRadius:9,background:C.navySoft,border:"1px solid #dbe2f0"}}><Calendar size={15} color={C.navy} /><select value={comp} onChange={e=>setComp(e.target.value)} style={{border:"none",background:"transparent",fontSize:13,fontWeight:700,color:C.navy,cursor:"pointer"}}>{COMPS.slice().reverse().map(c=><option key={c} value={c}>{compLabel(c)}</option>)}</select></div>}
          {(act==="fiscal"||act==="pessoal")&&<div style={{display:"flex",borderRadius:9,border:`1px solid ${C.line}`,overflow:"hidden"}}>{[["lista","Lista"],["planilha","Planilha"]].map(([k,l])=><button key={k} onClick={()=>setView(k)} style={{padding:"8px 13px",border:"none",background:view===k?C.navy:C.card,color:view===k?"#fff":C.body,fontSize:12.5,fontWeight:700,cursor:"pointer"}}>{l}</button>)}</div>}
          {act==="central"&&<button onClick={()=>canManageCentral?setAdding(true):notify("Apenas Admin e Financeiro incluem empresas.","deny")} style={{display:"flex",alignItems:"center",gap:7,padding:"9px 13px",borderRadius:9,cursor:"pointer",fontSize:13,fontWeight:700,background:canManageCentral?C.navy:C.bg,color:canManageCentral?"#fff":C.muted,border:canManageCentral?"none":`1px solid ${C.line}`}}>{canManageCentral?<Plus size={16} />:<Lock size={14} />} Nova empresa</button>}
          {act==="equipe"&&<button onClick={()=>setEmpEdit({})} style={{display:"flex",alignItems:"center",gap:7,padding:"9px 13px",borderRadius:9,cursor:"pointer",fontSize:13,fontWeight:700,background:C.navy,color:"#fff",border:"none"}}><UserPlus size={16} /> Novo funcionário</button>}
          {showFilters&&<div style={{position:"relative"}}><Search size={15} color={C.muted} style={{position:"absolute",left:11,top:10}} /><input value={query} onChange={e=>setQuery(e.target.value)} placeholder="Buscar…" style={{padding:"8px 12px 8px 32px",width:180,borderRadius:8,border:`1px solid ${C.line}`,background:C.bg,fontSize:13,color:C.ink}} /></div>}
        </header>

        {showFilters&&<FilterBar f={f} setF={setF} municipios={municipios} respOpts={respOpts} />}

        <section style={{flex:1,minHeight:0,display:"flex",flexDirection:"column",padding:"16px 24px 18px"}}>
          {act==="dashboard"&&<Dashboard me={me} isAdmin={isAdmin} comp={comp} canView={canView} statsOf={statsOf} inComp={inComp} getPD={getPD} go={setActive} />}
          {act!=="dashboard"&&act!=="equipe"&&act!=="historico"&&<PermissionNote act={act} isAdmin={isAdmin} canManageCentral={canManageCentral} canEditDept={canEditDept} comp={comp} />}
          {act==="central"&&<Central list={centralList} inCompN={inComp.length} comp={comp} canManage={canManageCentral} sort={sort} setSort={setSort} editId={editId} draft={draft} setDraft={setDraft} startEdit={(c)=>{if(!canManageCentral)return notify("Apenas Admin e Financeiro editam o cadastro.","deny");setEditId(c.id);setDraft({...c});}} saveEdit={()=>{const orig=registry.find(c=>c.id===editId)||{};const patch={codigo:draft.codigo,razao:draft.razao,cnpj:draft.cnpj,regime:draft.regime,municipio:draft.municipio,situacao:draft.situacao,dataSituacao:draft.situacao==="Ativo"?"":draft.dataSituacao};const ch=Object.keys(patch).filter(k=>(orig[k]??"")!==(patch[k]??"")).map(k=>CLABEL[k]+": "+disp(orig[k])+" → "+disp(patch[k]));updateReg(editId,patch,`Cadastro · ${draft.razao}: ${ch.length?ch.join("; "):"sem alterações"}`);setEditId(null);notify("Cadastro atualizado.","ok");}} cancel={()=>setEditId(null)} delId={delId} setDelId={setDelId} doDelete={(id,razao)=>{mutate(prev=>({...prev,registry:prev.registry.filter(c=>c.id!==id)}),`Excluiu empresa — ${razao}`);setDelId(null);notify("Empresa excluída.","ok");}} notify={notify} />}
          {(act==="fiscal"||act==="pessoal")&&<><ModuleHeader kind={act} stats={modStats} comp={comp} />{view==="lista"?<DeptList kind={act} list={deptList} getPD={getPD} open={setOpenId} sort={sort} setSort={setSort} />:<DeptGrid kind={act} list={deptList} getPD={getPD} open={setOpenId} sort={sort} setSort={setSort} canEdit={(c)=>canEditFicha(c,act)} editCell={editCell} />}</>}
          {OTHER_DEPTS.includes(act)&&<BlankDept dept={DEPTS.find(d=>d.key===act)} />}
          {act==="equipe"&&<Equipe employees={employees} registry={registry} onEdit={setEmpEdit} />}
          {act==="historico"&&<Historico log={db.log||[]} />}
        </section>
      </main>

      {adding&&<AddModal onClose={()=>setAdding(false)} nextCode={Math.max(0,...registry.map(c=>+c.codigo||0))+1} onSave={(nc)=>{mutate(prev=>({...prev,registry:[{...nc,id:Math.max(0,...prev.registry.map(c=>c.id))+1,respFiscal:"",respPessoal:""},...prev.registry]}),`Incluiu empresa — ${nc.razao}`);setAdding(false);notify("Empresa incluída.","ok");}} />}
      {opened&&(act==="fiscal"||act==="pessoal")&&<Ficha company={opened} pd={getPD(opened)} kind={act} comp={comp} canEdit={canEditFicha(opened,act)} canAssign={canAssignHere(act)} meName={me.nome} deptEmps={deptEmps(employees,act)} onClose={()=>setOpenId(null)} onSave={saveFicha} />}
      {empEdit&&<EmpModal emp={empEdit} employees={employees} onClose={()=>setEmpEdit(null)} onSave={(e)=>{mutate(prev=>{let list;if(e.id){list=prev.employees.map(x=>x.id===e.id?e:x);}else{list=[...prev.employees,{...e,id:Math.max(0,...prev.employees.map(x=>x.id))+1}];}return {...prev,employees:list};},`Equipe — salvou ${e.nome}`);setEmpEdit(null);notify("Funcionário salvo.","ok");}} onDelete={(id,nome)=>{mutate(prev=>({...prev,employees:prev.employees.filter(x=>x.id!==id)}),`Equipe — removeu ${nome}`);setEmpEdit(null);notify("Funcionário removido.","ok");}} />}
      {toast&&<div style={{position:"absolute",bottom:18,left:"50%",transform:"translateX(-50%)",animation:"pop .2s ease",background:toast.kind==="deny"?C.red:C.navy,color:"#fff",padding:"11px 18px",borderRadius:10,fontSize:13,fontWeight:600,display:"flex",alignItems:"center",gap:8,boxShadow:"0 8px 24px rgba(12,22,64,.25)",zIndex:40}}>{toast.kind==="deny"?<Lock size={15}/>:<Check size={15}/>}{toast.m}</div>}
    </div>
  );
}

function NavItem({icon:Icon,label,hint,dot,on,onClick}){return <button onClick={onClick} className="navb" style={{width:"100%",display:"flex",alignItems:"center",gap:10,padding:"9px 11px",margin:"2px 0",borderRadius:8,border:"none",cursor:"pointer",textAlign:"left",background:on?C.navySoft:"transparent",color:on?C.navy:C.body,fontSize:13.5,fontWeight:on?700:500,borderLeft:on?`3px solid ${C.navy}`:"3px solid transparent"}}><Icon size={16} color={on?C.navy:C.muted} /><span style={{flex:1}}>{label}</span>{hint&&<Pill bg={C.navySoft} fg={C.navy}>{hint}</Pill>}{dot&&<Dot size={18} color={C.navy} />}</button>;}
function Splash(){return <div style={{display:"grid",placeItems:"center",height:"100vh",background:C.bg}}><style>{FONTS}</style><div style={{textAlign:"center",color:C.muted}}><Loader size={26} color={C.navy} style={{animation:"spin 1s linear infinite"}} /><div style={{marginTop:10,fontSize:13,fontWeight:600}}>Carregando dados…</div></div></div>;}

function Dashboard({me,isAdmin,comp,canView,statsOf,inComp,getPD,go}){
  const depts=["fiscal","pessoal"].filter(d=>canView(d));
  const [fd,setFd]=useState("todos");
  const cards=depts.map(d=>({d,label:DEPT_LABEL[d],st:statsOf(d,inComp)}));
  const myName=me.nome;
  const minhas=inComp.filter(c=>(c.respFiscal===myName||c.respPessoal===myName));
  const pend=[];
  const useDepts=fd==="todos"?depts:[fd];
  useDepts.forEach(d=>{inComp.forEach(c=>{ if(me.onlyAssigned&&!isAdmin){ const r=d==="fiscal"?c.respFiscal:c.respPessoal; if(r!==myName)return; } const pd=getPD(c); const ex=d==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c); const v=d==="fiscal"?fiscalNum(pd):pessoalNum(pd,c); if(!ex&&v<100) pend.push({c,d,v}); });});
  pend.sort((a,b)=>a.v-b.v);
  return <div style={{flex:1,minHeight:0,display:"flex",flexDirection:"column",gap:16,overflow:"auto"}}>
    <div style={{background:C.navyDeep,borderRadius:14,padding:"20px 24px",color:"#fff",position:"relative",overflow:"hidden",flexShrink:0}}>
      <div style={{position:"absolute",right:-80,top:-50,width:240,height:240,borderRadius:"50%",background:"radial-gradient(circle, rgba(144,152,152,.16), transparent 70%)"}} />
      <div style={{position:"relative"}}><div style={{fontSize:13,color:"#b9c0d4"}}>Olá, {me.nome.split(" ")[0]} 👋</div>
      <div style={{fontSize:22,fontWeight:800,marginTop:2}}>Painel — {compLabel(comp)}</div>
      <div style={{fontSize:12.5,color:"#b9c0d4",marginTop:4}}>{isAdmin?"Visão geral de todos os departamentos.":`Seu acesso: ${depts.map(d=>DEPT_LABEL[d]).join(", ")||"—"}`}</div></div>
    </div>
    <div style={{display:"flex",gap:16,flexWrap:"wrap",flexShrink:0}}>
      {cards.length===0&&<div style={{color:C.muted,fontSize:13}}>Sem departamentos de progresso liberados no seu acesso.</div>}
      {cards.map(({d,label,st})=>(<div key={d} onClick={()=>go(d)} style={{flex:1,minWidth:280,background:C.card,border:`1px solid ${C.line}`,borderRadius:14,padding:"18px 20px",cursor:"pointer"}}>
        <div style={{display:"flex",alignItems:"center",justifyContent:"space-between"}}><span style={{fontSize:13,fontWeight:700,color:C.ink}}>{label}</span><ChevronRight size={16} color={C.muted} /></div>
        <div style={{display:"flex",alignItems:"baseline",gap:10,margin:"8px 0 8px"}}><span className="tnum" style={{fontSize:38,fontWeight:800,color:barColor(st.avg),letterSpacing:-1.5}}>{st.avg}%</span><span style={{fontSize:12.5,color:C.muted}}>progresso médio</span></div>
        <Bar pct={st.avg} />
        <div style={{display:"flex",gap:16,marginTop:12}}><Mini n={st.tot} l="empresas" c={C.navy} /><Mini n={st.c100} l="a 100%" c={C.green} /><Mini n={st.pend} l="pendentes" c={C.amber} /><Mini n={st.na} l={d==="fiscal"?"sem movim.":"sem folha"} c={C.muted} /></div>
        {d==="fiscal"&&<div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"6px 14px",marginTop:14}}>{OBRIG.map(([lb,k])=>(<div key={k}><div style={{display:"flex",justifyContent:"space-between",fontSize:10.5,color:C.muted,marginBottom:3}}><span>{lb}</span><span className="tnum" style={{fontWeight:700,color:barColor(st.obrig[k])}}>{st.obrig[k]}%</span></div><Bar pct={st.obrig[k]} /></div>))}</div>}
      </div>))}
    </div>
    <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:14,display:"flex",flexDirection:"column",overflow:"hidden"}}>
      <div style={{padding:"13px 18px",borderBottom:`1px solid ${C.line}`,display:"flex",alignItems:"center",gap:8,flexShrink:0}}><AlertCircle size={16} color={C.amber} /><span style={{fontSize:13,fontWeight:700,color:C.ink}}>Pendências {me.onlyAssigned&&!isAdmin?"atribuídas a você":"do seu acesso"}</span><span style={{fontSize:12,color:C.muted}}>· {pend.length}</span>{depts.length>1&&<div style={{marginLeft:"auto",display:"flex",gap:4}}>{["todos",...depts].map(d=>(<button key={d} onClick={()=>setFd(d)} style={{padding:"5px 11px",borderRadius:7,border:`1px solid ${fd===d?C.navy:C.line}`,background:fd===d?C.navySoft:C.card,color:fd===d?C.navy:C.body,fontSize:12,fontWeight:700,cursor:"pointer"}}>{d==="todos"?"Todos":DEPT_LABEL[d]}</button>))}</div>}</div>
      <div style={{flex:1,overflow:"auto"}}><table style={tbl}><thead style={sticky}><tr style={trh}><th style={th}>Empresa</th><th style={th}>Depto</th><th style={th}>Progresso</th></tr></thead>
        <tbody>{pend.map(({c,d,v},i)=>(<tr key={i} className="rowh" style={trb}><td style={td}><div style={{fontWeight:700}}>{c.razao}</div><div style={{fontSize:11,color:C.muted}} className="tnum">{c.cnpj} · cód {c.codigo}</div></td><td style={td}><Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">{DEPT_LABEL[d]}</Pill></td><td style={td}><RowProg excl={null} prog={v} /></td></tr>))}
        {pend.length===0&&<tr><td colSpan={3} style={{...td,textAlign:"center",color:C.green,padding:30,fontWeight:600}}>Tudo em dia nesta competência. ✓</td></tr>}</tbody></table></div>
    </div>
  </div>;
}
function Mini({n,l,c}){return <div><div className="tnum" style={{fontSize:18,fontWeight:800,color:c}}>{n}</div><div style={{fontSize:11,color:C.muted}}>{l}</div></div>;}

function FilterBar({f,setF,municipios,respOpts}){
  const sel=(key,label,opts)=>(<div style={{display:"flex",flexDirection:"column",gap:3}}><span style={{fontSize:10,fontWeight:700,color:C.muted,letterSpacing:.4,textTransform:"uppercase"}}>{label}</span><select value={f[key]} onChange={e=>setF({...f,[key]:e.target.value})} style={{padding:"7px 10px",borderRadius:8,border:`1px solid ${C.line}`,background:C.card,fontSize:12.5,fontWeight:600,color:C.ink,cursor:"pointer",minWidth:116}}><option value="todos">Todos</option>{opts.map(o=><option key={o} value={o}>{o}</option>)}</select></div>);
  const dirty=Object.values(f).some(v=>v!=="todos");
  return <div style={{display:"flex",alignItems:"flex-end",gap:11,padding:"10px 24px",background:C.card,borderBottom:`1px solid ${C.line}`,flexShrink:0,flexWrap:"wrap"}}>
    <div style={{display:"flex",alignItems:"center",gap:6,color:C.navy,fontSize:12.5,fontWeight:700,marginBottom:7}}><Filter size={15} /> Filtros</div>
    {sel("regime","Regime",["SIMPLES NACIONAL","LUCRO PRESUMIDO","LUCRO REAL","PRODUTOR RURAL","DOMÉSTICA","ASSOCIAÇÃO PRIVADA","MEI"])}{sel("municipio","Município",municipios)}{sel("situacao","Situação",["Ativo","Inativo","Bloqueada"])}
    {respOpts&&sel("resp","Responsável",respOpts)}
    {dirty&&<button onClick={()=>setF({regime:"todos",municipio:"todos",situacao:"todos",resp:"todos"})} style={{marginBottom:1,padding:"7px 12px",borderRadius:8,border:`1px solid ${C.line}`,background:C.bg,color:C.body,fontSize:12.5,fontWeight:600,cursor:"pointer"}}>Limpar</button>}
  </div>;
}
function PermissionNote({act,isAdmin,canManageCentral,canEditDept,comp}){
  if(act==="central")return <Note ok={canManageCentral} txt={canManageCentral?`Você inclui, edita, exclui e define a situação. Competência: ${compLabel(comp)}.`:"Somente leitura. Incluir, excluir e mudar situação são de Admin e Financeiro."} />;
  if(OTHER_DEPTS.includes(act))return null;
  const can=canEditDept(act);
  return <Note ok={can} txt={can?(isAdmin?`Administrador — você edita as fichas de ${compLabel(comp)}.`:`Você edita as fichas das empresas do seu departamento em ${compLabel(comp)} (conforme suas permissões).`):"Somente leitura. Apenas o gestor deste departamento (ou Admin) edita."} />;
}
function Note({ok,txt}){const Icon=ok?ShieldCheck:Eye;return <div style={{display:"flex",alignItems:"center",gap:9,background:ok?C.greenSoft:C.bg,border:`1px solid ${ok?"#cfe3d6":C.line}`,borderRadius:9,padding:"9px 13px",marginBottom:14,fontSize:12.5,color:C.ink,flexShrink:0}}><Icon size={15} color={ok?C.green:C.muted} /><span>{txt}</span></div>;}

function ModuleHeader({kind,stats,comp}){if(!stats)return null;
  return <div style={{display:"flex",gap:14,marginBottom:12,flexWrap:"wrap",flexShrink:0}}>
    <div style={{flex:1,minWidth:260,background:C.card,border:`1px solid ${C.line}`,borderRadius:12,padding:"14px 18px"}}>
      <div style={{display:"flex",alignItems:"baseline",justifyContent:"space-between"}}><span style={{fontSize:12.5,fontWeight:700,color:C.ink}}>Progresso médio · {DEPT_LABEL[kind]}</span><span className="tnum" style={{fontSize:26,fontWeight:800,color:barColor(stats.avg),letterSpacing:-1}}>{stats.avg}%</span></div>
      <div style={{margin:"8px 0 6px"}}><Bar pct={stats.avg} /></div>
      <div style={{fontSize:11.5,color:C.muted}}>{stats.tot} empresas · {stats.c100} a 100% · {stats.pend} pendentes · {stats.na} sem demanda — {compLabel(comp)}</div>
    </div>
    {kind==="fiscal"&&<div style={{flex:2,minWidth:320,display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:9}}>{OBRIG.map(([label,k])=>{const pct=stats.obrig[k]||0;return <div key={k} style={{background:C.card,border:`1px solid ${C.line}`,borderRadius:10,padding:"8px 11px"}}><div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:5}}><span style={{fontSize:10.5,fontWeight:700,color:C.ink}}>{label}</span><span className="tnum" style={{fontSize:11.5,fontWeight:800,color:barColor(pct)}}>{pct}%</span></div><Bar pct={pct} /></div>;})}</div>}
  </div>;
}

function SortTH({label,k,sort,setSort}){const active=sort.key===k;return <th style={{...th,cursor:"pointer",userSelect:"none"}} className="sorth" onClick={()=>setSort(active?{key:k,dir:-sort.dir}:{key:k,dir:1})}><span style={{display:"inline-flex",alignItems:"center",gap:3,color:active?C.navy:"inherit"}}>{label}{active?(sort.dir===1?<ArrowUp size={12}/>:<ArrowDown size={12}/>):<ArrowUp size={11} style={{opacity:.25}}/>}</span></th>;}

function Central({list,inCompN,comp,canManage,sort,setSort,editId,draft,setDraft,startEdit,saveEdit,cancel,delId,setDelId,doDelete,notify}){
  const inat=list.filter(c=>c.situacao!=="Ativo").length;
  return (<>
    <div style={{display:"flex",gap:14,marginBottom:12,flexWrap:"wrap",flexShrink:0}}>
      <Stat label="Total cadastradas" value={list.length} icon={Building2} />
      <Stat label={`Ativas em ${compLabel(comp)}`} value={inCompN} icon={Calendar} accent={C.green} />
      <Stat label="Inativas / Bloqueadas" value={inat} icon={Lock} accent={C.red} />
    </div>
    <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:11,overflow:"hidden",display:"flex",flexDirection:"column"}}><div style={{flex:1,overflow:"auto"}}><table style={tbl}><thead style={sticky}><tr style={trh}><SortTH label="Cód." k="codigo" sort={sort} setSort={setSort} /><SortTH label="Razão social" k="razao" sort={sort} setSort={setSort} /><SortTH label="CNPJ" k="cnpj" sort={sort} setSort={setSort} /><th style={th}>Regime</th><th style={th}>Município</th><th style={th}>Situação</th><th style={th}>Desde</th><th style={th}></th></tr></thead>
      <tbody>{list.map(c=>{const ed=editId===c.id;const del=delId===c.id;
        return <tr key={c.id} className="rowh" style={trb}>
          <td style={{...td,color:C.muted}} className="tnum">{ed?<input value={draft.codigo} onChange={e=>setDraft({...draft,codigo:e.target.value})} style={{...cellInp,width:64}} />:c.codigo}</td>
          <td style={td}>{ed?<input value={draft.razao} onChange={e=>setDraft({...draft,razao:e.target.value})} style={cellInp} />:<span style={{fontWeight:700}}>{c.razao}</span>}</td>
          <td style={{...td,color:C.body}} className="tnum">{ed?<input value={draft.cnpj} onChange={e=>setDraft({...draft,cnpj:e.target.value})} style={cellInp} />:c.cnpj}</td>
          <td style={td}>{ed?<select value={draft.regime} onChange={e=>setDraft({...draft,regime:e.target.value})} style={cellInp}>{["SIMPLES NACIONAL","LUCRO PRESUMIDO","LUCRO REAL","PRODUTOR RURAL","DOMÉSTICA","ASSOCIAÇÃO PRIVADA","MEI","—"].map(o=><option key={o}>{o}</option>)}</select>:<Pill bg={C.bg} fg={C.body} br={C.line}>{c.regime}</Pill>}</td>
          <td style={{...td,color:C.body}}>{ed?<input value={draft.municipio} onChange={e=>setDraft({...draft,municipio:e.target.value})} style={cellInp} />:c.municipio}</td>
          <td style={td}>{ed?<select value={draft.situacao} onChange={e=>setDraft({...draft,situacao:e.target.value})} style={cellInp}>{["Ativo","Inativo","Bloqueada"].map(o=><option key={o}>{o}</option>)}</select>:<StatusPill s={c.situacao} />}</td>
          <td style={{...td,color:C.body}} className="tnum">{ed?(draft.situacao!=="Ativo"?<input type="date" value={draft.dataSituacao||""} onChange={e=>setDraft({...draft,dataSituacao:e.target.value})} style={cellInp} />:<span style={{color:C.muted}}>—</span>):(c.situacao!=="Ativo"&&c.dataSituacao?c.dataSituacao:"—")}</td>
          <td style={{...td,textAlign:"right",whiteSpace:"nowrap"}}>{ed?<div style={{display:"flex",gap:6,justifyContent:"flex-end"}}><button onClick={saveEdit} style={iconBtn(C.navy)}><Check size={15}/></button><button onClick={cancel} style={iconBtn(C.muted)}><X size={15}/></button></div>:del?<div style={{display:"flex",gap:6,justifyContent:"flex-end",alignItems:"center"}}><span style={{fontSize:11.5,color:C.red,fontWeight:600}}>Excluir?</span><button onClick={()=>doDelete(c.id,c.razao)} style={iconBtn(C.red)}><Check size={15}/></button><button onClick={()=>setDelId(null)} style={iconBtn(C.muted)}><X size={15}/></button></div>:<div style={{display:"flex",gap:6,justifyContent:"flex-end"}}><button onClick={()=>startEdit(c)} style={iconBtn(canManage?C.muted:"#c9cdd6")}>{canManage?<Pencil size={14}/>:<Lock size={13}/>}</button><button onClick={()=>canManage?setDelId(c.id):notify("Apenas Admin e Financeiro excluem.","deny")} style={iconBtn(canManage?C.red:"#c9cdd6")}>{canManage?<Trash2 size={14}/>:<Lock size={13}/>}</button></div>}</td>
        </tr>;})}
      {list.length===0&&<tr><td colSpan={8} style={{...td,textAlign:"center",color:C.muted,padding:30}}>Nenhuma empresa com os filtros atuais.</td></tr>}
    </tbody></table></div></div></>);
}

function DeptList({kind,list,getPD,open,sort,setSort}){
  return <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:11,overflow:"hidden",display:"flex",flexDirection:"column"}}><div style={{flex:1,overflow:"auto"}}><table style={tbl}><thead style={sticky}><tr style={trh}>
    <SortTH label="Cód." k="codigo" sort={sort} setSort={setSort} /><SortTH label="Razão social" k="razao" sort={sort} setSort={setSort} /><SortTH label="CNPJ" k="cnpj" sort={sort} setSort={setSort} />
    {kind==="fiscal"&&<th style={th}>Município</th>}<th style={th}>{kind==="fiscal"?"Resp. Fiscal":"Resp. Pessoal"}</th><th style={th}>{kind==="fiscal"?"Regime":"Tipo folha"}</th><th style={th}>Concl.</th><th style={th}>Progresso</th><th style={th}></th></tr></thead>
    <tbody>{list.map(c=>{const pd=getPD(c);const excl=kind==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c);const prog=kind==="fiscal"?fiscalNum(pd):pessoalNum(pd,c);
      return <tr key={c.id} className="rowh" style={{...trb,cursor:"pointer"}} onClick={()=>open(c.id)}>
        <td style={{...td,color:C.muted}} className="tnum">{c.codigo}</td>
        <td style={td}><span style={{fontWeight:700}}>{c.razao}</span></td>
        <td style={{...td,color:C.body}} className="tnum">{c.cnpj}</td>
        {kind==="fiscal"&&<td style={{...td,color:C.body}}>{c.municipio||"—"}</td>}
        <td style={{...td,color:C.body}}>{(kind==="fiscal"?c.respFiscal:c.respPessoal)||<span style={{color:C.muted}}>— definir —</span>}</td>
        {kind==="fiscal"?<td style={td}><Pill bg={C.bg} fg={C.body} br={C.line}>{c.regime}</Pill></td>:<td style={td}><Pill bg={C.amberSoft} fg={C.amber} br="#ecdcb6">{pd.pessoal.tipoFolha||c.tipoFolha}</Pill></td>}
        <td style={td}>{excl?<Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">{excl}</Pill>:<StatusPill s={kind==="fiscal"?pd.fiscal.fiscalConcluido:pd.pessoal.pessoalConcluido} />}</td>
        <td style={td}><RowProg excl={excl} prog={prog} /></td>
        <td style={{...td,textAlign:"right"}}><span style={{display:"inline-flex",alignItems:"center",gap:3,color:C.navy,fontSize:12.5,fontWeight:700}}>Ficha <ChevronRight size={14} /></span></td>
      </tr>;})}
      {list.length===0&&<tr><td colSpan={kind==="fiscal"?9:8} style={{...td,textAlign:"center",color:C.muted,padding:30}}>Nenhuma empresa com os filtros atuais.</td></tr>}
    </tbody></table></div></div>;
}

function DeptGrid({kind,list,getPD,open,sort,setSort,canEdit,editCell}){
  const stL={position:"sticky",left:0,zIndex:2,background:C.card,boxShadow:"2px 0 0 "+C.line};
  const stLH={position:"sticky",left:0,top:0,zIndex:4,background:C.bg,boxShadow:"2px 0 0 "+C.line};
  const selSt={padding:"4px 6px",borderRadius:6,border:`1px solid ${C.line}`,background:"#fff",fontSize:12,color:C.ink,cursor:"pointer",minWidth:96};
  const Cell=({val,opts,can,onCh})=> can?<select value={val} onChange={e=>onCh(e.target.value)} style={selSt}>{opts.map(o=><option key={o}>{o}</option>)}</select>:<StatusPill s={val} />;
  const PL={holerites:"Holerites",vrCesta:"VR/Cesta",alocRPA:"RPA",fgts:"FGTS",darfDae:"DARF/DAE",dcomp:"DCOMP"};
  const cols=kind==="fiscal"?[{l:"Município",w:120},{l:"Resp.",w:110},{l:"Regime",w:140},...OBRIG.map(([l])=>({l,w:118})),{l:"Concluído",w:90},{l:"Confirm.",w:90},{l:"Progresso",w:120}]
    :[{l:"Resp.",w:110},{l:"Tipo folha",w:130},...PROC.map(k=>({l:PL[k],w:108})),{l:"Retific.",w:90},{l:"Concluído",w:90},{l:"Confirm.",w:90},{l:"Progresso",w:120}];
  const SortLbl=({label,k})=>{const a=sort.key===k;return <span onClick={()=>setSort(a?{key:k,dir:-sort.dir}:{key:k,dir:1})} style={{cursor:"pointer",color:a?C.navy:"inherit",display:"inline-flex",alignItems:"center",gap:2}}>{label}{a?(sort.dir===1?<ArrowUp size={11}/>:<ArrowDown size={11}/>):null}</span>;};
  return <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:11,overflow:"hidden",display:"flex",flexDirection:"column"}}>
    <div style={{flex:1,overflow:"auto"}}><table style={{borderCollapse:"collapse",fontSize:12.5,whiteSpace:"nowrap"}}>
      <thead style={{position:"sticky",top:0,zIndex:3}}><tr style={trh}>
        <th style={{...th,...stLH,minWidth:236}}><span style={{display:"inline-flex",gap:10}}><SortLbl label="Cód." k="codigo" /><SortLbl label="Empresa" k="razao" /></span></th>
        {cols.map(c=><th key={c.l} style={{...th,minWidth:c.w}}>{c.l}</th>)}<th style={th}></th>
      </tr></thead>
      <tbody>{list.map(c=>{const pd=getPD(c);const excl=kind==="fiscal"?fiscalExcl(pd):pessoalExcl(pd,c);const prog=kind==="fiscal"?fiscalNum(pd):pessoalNum(pd,c);const can=canEdit(c)&&!excl;const set=(mut)=>editCell(c,kind,mut);
        return <tr key={c.id} className="rowh" style={trb}>
          <td style={{...td,...stL}}><div style={{fontWeight:700,whiteSpace:"normal",maxWidth:220}}>{c.razao}</div><div style={{fontSize:10.5,color:C.muted}} className="tnum">cód {c.codigo} · {c.cnpj}</div></td>
          {kind==="fiscal"?<>
            <td style={{...td,color:C.body}}>{c.municipio||"—"}</td><td style={{...td,color:C.body}}>{c.respFiscal||"—"}</td><td style={td}><Pill bg={C.bg} fg={C.body} br={C.line}>{c.regime}</Pill></td>
            {excl?<td colSpan={OBRIG.length+2} style={{...td,textAlign:"center"}}><Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">{excl}</Pill></td>:<>
              {OBRIG.map(([l,k])=><td key={k} style={td}><Cell val={pd.fiscal.obrig[k].obrig} opts={OBRIG_ST} can={can} onCh={v=>set(p=>{p.fiscal.obrig[k].obrig=v;return p;})} /></td>)}
              <td style={td}><Cell val={pd.fiscal.fiscalConcluido} opts={SN} can={can} onCh={v=>set(p=>{p.fiscal.fiscalConcluido=v;return p;})} /></td>
              <td style={td}><Cell val={pd.fiscal.fiscalConfirmacao} opts={SN} can={can} onCh={v=>set(p=>{p.fiscal.fiscalConfirmacao=v;return p;})} /></td></>}
            <td style={td}><RowProg excl={excl} prog={prog} /></td></>:<>
            <td style={{...td,color:C.body}}>{c.respPessoal||"—"}</td><td style={td}><Pill bg={C.amberSoft} fg={C.amber} br="#ecdcb6">{pd.pessoal.tipoFolha||c.tipoFolha}</Pill></td>
            {excl?<td colSpan={PROC.length+3} style={{...td,textAlign:"center"}}><Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">{excl}</Pill></td>:<>
              {PROC.map(k=><td key={k} style={td}><Cell val={pd.pessoal[k]} opts={STAT_OPTS} can={can} onCh={v=>set(p=>{p.pessoal[k]=v;return p;})} /></td>)}
              <td style={td}><Cell val={pd.pessoal.retificacao} opts={SN} can={can} onCh={v=>set(p=>{p.pessoal.retificacao=v;return p;})} /></td>
              <td style={td}><Cell val={pd.pessoal.pessoalConcluido} opts={SN} can={can} onCh={v=>set(p=>{p.pessoal.pessoalConcluido=v;return p;})} /></td>
              <td style={td}><Cell val={pd.pessoal.confEnvio} opts={SN} can={can} onCh={v=>set(p=>{p.pessoal.confEnvio=v;return p;})} /></td></>}
            <td style={td}><RowProg excl={excl} prog={prog} /></td></>}
          <td style={td}><button onClick={()=>open(c.id)} style={{display:"inline-flex",alignItems:"center",gap:3,color:C.navy,fontSize:12,fontWeight:700,background:"none",border:"none",cursor:"pointer"}}>Ficha <ChevronRight size={13} /></button></td>
        </tr>;})}
        {list.length===0&&<tr><td style={{...td,textAlign:"center",color:C.muted,padding:30}}>Nenhuma empresa.</td></tr>}
      </tbody></table></div></div>;
}
function BlankDept({dept}){const Icon=dept.icon;return <div style={{flex:1,display:"grid",placeItems:"center",textAlign:"center",color:C.muted}}><div><div style={{width:54,height:54,borderRadius:14,background:C.card,border:`1px solid ${C.line}`,display:"grid",placeItems:"center",margin:"0 auto 14px"}}><Icon size={24} color={C.grey} /></div><div style={{fontSize:16,fontWeight:800,color:C.ink}}>Módulo {dept.label}</div><div style={{fontSize:13,maxWidth:380,marginTop:6,lineHeight:1.5}}>Ainda não estruturado. Envie a planilha deste departamento que montamos a ficha completa.</div></div></div>;}

function EmpSel({v,set,emps,disabled}){return <select value={v||""} disabled={disabled} onChange={e=>set(e.target.value)} style={{...cellInp,cursor:disabled?"not-allowed":"pointer"}}><option value="">— sem —</option>{emps.map(n=><option key={n}>{n}</option>)}</select>;}
function Field({row,val,onChange,disabled}){const base={width:"100%",padding:"8px 10px",borderRadius:8,border:`1px solid ${C.line}`,background:disabled?C.bg:"#fff",fontSize:13,color:C.ink};
  if(row.t==="sel"||row.t==="status"){const opts=row.t==="status"?STAT_OPTS:row.o;return <select value={val??""} disabled={disabled} onChange={e=>onChange(e.target.value)} style={{...base,cursor:disabled?"not-allowed":"pointer"}}>{opts.map(o=><option key={o}>{o}</option>)}</select>;}
  if(row.t==="date") return <input type="date" value={val??""} disabled={disabled} onChange={e=>onChange(e.target.value)} style={base} />;
  if(row.t==="money") return <input type="number" step="0.01" value={val??""} disabled={disabled} onChange={e=>onChange(e.target.value===""?"":Number(e.target.value))} style={base} placeholder="0,00" />;
  return <input value={val??""} disabled={disabled} onChange={e=>onChange(e.target.value)} style={base} />;}

function Ficha({company,pd,kind,comp,canEdit,canAssign,meName,deptEmps,onClose,onSave}){
  const [sm,setSm]=useState(!!pd.semMovimento);
  const [ff,setFf]=useState(()=>JSON.parse(JSON.stringify(pd.fiscal)));
  const [pf,setPf]=useState(()=>JSON.parse(JSON.stringify(pd.pessoal)));
  const [resp,setResp]=useState(kind==="fiscal"?company.respFiscal:company.respPessoal);
  const SECTIONS=kind==="fiscal"?FISCAL_FORM:PESSOAL_FORM;
  const setF=(k,v)=>setFf(o=>({...o,[k]:v})); const setP=(k,v)=>setPf(o=>({...o,[k]:v}));
  const setObrig=(key,sub,v)=>setFf(o=>({...o,obrig:{...o.obrig,[key]:{...o.obrig[key],[sub]:v}}}));
  const setNested=(grp,sub,v)=>setFf(o=>({...o,[grp]:{...o[grp],[sub]:v}}));
  const prog=kind==="fiscal"?(sm?100:fiscalNum({semMovimento:sm,fiscal:ff})):((sm||(pf.tipoFolha==="SEM FOLHA"))?100:pessoalNum({semMovimento:sm,pessoal:pf},company));
  const excl=kind==="fiscal"?(sm?"S/M":null):(sm?"S/M":(pf.tipoFolha==="SEM FOLHA"?"Sem folha":null));
  const dirty=canEdit||canAssign;
  const save=()=>{const regPatch=(canAssign)?(kind==="fiscal"?(resp!==company.respFiscal?{respFiscal:resp}:{}):(resp!==company.respPessoal?{respPessoal:resp}:{})):{};const newPD={semMovimento:sm,_meta:{by:meName,at:Date.now()},fiscal:kind==="fiscal"?ff:pd.fiscal,pessoal:kind==="pessoal"?pf:pd.pessoal};onSave(regPatch,newPD);};
  return <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(12,22,64,.4)",zIndex:30,display:"flex",justifyContent:"flex-end"}}>
    <div onClick={e=>e.stopPropagation()} style={{width:580,maxWidth:"95%",height:"100%",background:C.bg,animation:"slin .22s ease",display:"flex",flexDirection:"column"}}>
      <div style={{background:C.card,borderBottom:`1px solid ${C.line}`,padding:"15px 22px",display:"flex",alignItems:"center",gap:12,flexShrink:0}}>
        <div style={{flex:1,minWidth:0}}><div style={{fontSize:10.5,color:C.muted,letterSpacing:1,textTransform:"uppercase",fontWeight:700}}>Ficha {kind==="fiscal"?"Fiscal":"Pessoal"} · {compLabel(comp)} · cód {company.codigo}</div>
          <div style={{fontSize:17,fontWeight:800,color:C.ink,whiteSpace:"nowrap",overflow:"hidden",textOverflow:"ellipsis"}}>{company.razao}</div>
          <div style={{fontSize:11.5,color:C.muted}} className="tnum">{company.cnpj} · {company.regime} · {company.municipio}</div></div>
        <div style={{textAlign:"center"}}>{excl?<Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">{excl}</Pill>:<><div className="tnum" style={{fontSize:22,fontWeight:800,color:barColor(prog)}}>{prog}%</div><div style={{width:60}}><Bar pct={prog} /></div></>}</div>
        <button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={20} /></button>
      </div>
      {!canEdit&&<div style={{margin:"12px 22px 0",background:C.bg,border:`1px solid ${C.line}`,borderRadius:9,padding:"9px 13px",fontSize:12.5,color:C.muted,display:"flex",gap:8,alignItems:"center",flexShrink:0}}><Eye size={15} /> Somente leitura — esta empresa não está atribuída a você (ou você não edita este departamento).</div>}
      {pd._meta&&<div style={{margin:"12px 22px 0",fontSize:11.5,color:C.muted,flexShrink:0}}>Última alteração: <b style={{color:C.body}}>{pd._meta.by}</b> em {fmtDT(pd._meta.at)}</div>}
      <div style={{flex:1,overflow:"auto",padding:"14px 22px 20px"}}>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12,marginBottom:14}}>
          <div><label style={fl}>Responsável ({kind==="fiscal"?"Fiscal":"Pessoal"})</label><EmpSel v={resp} set={setResp} emps={deptEmps} disabled={!canAssign} />{!canAssign&&<div style={{fontSize:10.5,color:C.muted,marginTop:3}}>Só quem tem permissão de atribuição altera.</div>}</div>
        </div>
        {kind==="fiscal"&&<div style={{background:sm?C.navySoft:C.bg,border:`1px solid ${sm?"#dbe2f0":C.line}`,borderRadius:10,padding:"11px 14px",display:"flex",alignItems:"center",gap:10,marginBottom:14}}><input type="checkbox" checked={sm} disabled={!canEdit} onChange={e=>setSm(e.target.checked)} style={{width:16,height:16,cursor:canEdit?"pointer":"not-allowed"}} /><div style={{flex:1}}><div style={{fontSize:13,fontWeight:700,color:C.ink}}>Sem movimento no período (S/M)</div><div style={{fontSize:11.5,color:C.muted}}>O Pessoal verá isso e a empresa sai do cálculo de progresso.</div></div>{sm&&<Pill bg={C.navy} fg="#fff">S/M</Pill>}</div>}
        {kind==="pessoal"&&<div style={{background:C.navySoft,border:"1px solid #dbe2f0",borderRadius:10,padding:"11px 14px",marginBottom:14}}><div style={{fontSize:11,fontWeight:700,color:C.navy,letterSpacing:.4,textTransform:"uppercase",marginBottom:6,display:"flex",alignItems:"center",gap:6}}><Eye size={13} /> Vindo do Fiscal (somente leitura)</div><div style={{display:"flex",gap:18,fontSize:12.5,color:C.ink}}><span>EFD REINF: <StatusPill s={pd.fiscal.obrig.efdreinf.obrig} /></span>{pd.fiscal.obrig.efdreinf.data&&<span style={{color:C.muted}}>em {pd.fiscal.obrig.efdreinf.data}</span>}{pd.semMovimento&&<span><b>SEM MOVIMENTO</b></span>}</div></div>}
        {SECTIONS.map(s=><div key={s.sec} style={{marginBottom:16}}><div style={secT}>{s.sec}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"12px 14px"}}>{s.rows.map(r=><div key={r.k}><label style={fl}>{r.l}</label><Field row={r} val={(kind==="fiscal"?ff:pf)[r.k]} disabled={!canEdit} onChange={v=>(kind==="fiscal"?setF:setP)(r.k,v)} /></div>)}</div></div>)}
        {kind==="fiscal"&&<>
          <div style={secT}>Obrigações acessórias</div>
          <div style={{background:C.card,border:`1px solid ${C.line}`,borderRadius:10,overflow:"hidden"}}><table style={{...tbl,fontSize:12.5}}><thead><tr style={trh}><th style={th}>Obrigação</th><th style={th}>Status</th><th style={th}>Data</th><th style={th}>RET</th></tr></thead><tbody>{OBRIG.map(([label,key])=><tr key={key} style={trb}><td style={{...td,fontWeight:600}}>{label}{key==="efdreinf"&&<span style={{fontSize:10,color:C.navy,marginLeft:6}}>→ Pessoal</span>}</td><td style={{...td,width:140}}><select value={ff.obrig[key].obrig} disabled={!canEdit} onChange={e=>setObrig(key,"obrig",e.target.value)} style={{width:"100%",padding:"6px 8px",borderRadius:7,border:`1px solid ${C.line}`,background:canEdit?"#fff":C.bg,fontSize:12.5,color:C.ink,cursor:canEdit?"pointer":"not-allowed"}}>{OBRIG_ST.map(o=><option key={o}>{o}</option>)}</select></td><td style={{...td,width:140}}><input type="date" value={ff.obrig[key].data} disabled={!canEdit} onChange={e=>setObrig(key,"data",e.target.value)} style={{width:"100%",padding:"6px 8px",borderRadius:7,border:`1px solid ${C.line}`,background:canEdit?"#fff":C.bg,fontSize:12,color:C.ink}} /></td><td style={{...td,width:80}}><input value={ff.obrig[key].ret} disabled={!canEdit} onChange={e=>setObrig(key,"ret",e.target.value)} style={{width:"100%",padding:"6px 8px",borderRadius:7,border:`1px solid ${C.line}`,background:canEdit?"#fff":C.bg,fontSize:12,color:C.ink}} placeholder="—" /></td></tr>)}</tbody></table></div>
          {[["coordFiscal","Coordenadora Fiscal"],["depContabil","Departamento Contábil"]].map(([grp,t])=><div key={grp} style={{marginTop:16}}><div style={secT}>{t}</div><div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1.4fr",gap:12}}><div><label style={fl}>Finalizada</label><select value={ff[grp].fin} disabled={!canEdit} onChange={e=>setNested(grp,"fin",e.target.value)} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:`1px solid ${C.line}`,background:canEdit?"#fff":C.bg,fontSize:13,color:C.ink,cursor:canEdit?"pointer":"not-allowed"}}>{SN.map(o=><option key={o}>{o}</option>)}</select></div><div><label style={fl}>Data</label><input type="date" value={ff[grp].data} disabled={!canEdit} onChange={e=>setNested(grp,"data",e.target.value)} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:`1px solid ${C.line}`,background:canEdit?"#fff":C.bg,fontSize:13,color:C.ink}} /></div><div><label style={fl}>Observação</label><input value={ff[grp].obs} disabled={!canEdit} onChange={e=>setNested(grp,"obs",e.target.value)} style={{width:"100%",padding:"8px 10px",borderRadius:8,border:`1px solid ${C.line}`,background:canEdit?"#fff":C.bg,fontSize:13,color:C.ink}} /></div></div></div>)}
        </>}
      </div>
      {dirty&&<div style={{background:C.card,borderTop:`1px solid ${C.line}`,padding:"12px 22px",display:"flex",gap:10,justifyContent:"flex-end",flexShrink:0}}><button onClick={onClose} style={{padding:"10px 18px",borderRadius:9,border:`1px solid ${C.line}`,background:C.bg,color:C.body,fontWeight:700,fontSize:13.5,cursor:"pointer"}}>Cancelar</button><button onClick={save} style={{padding:"10px 20px",borderRadius:9,border:"none",background:C.navy,color:"#fff",fontWeight:700,fontSize:13.5,cursor:"pointer",display:"flex",alignItems:"center",gap:7}}><Save size={16} /> Salvar</button></div>}
    </div></div>;
}

function Equipe({employees,registry,onEdit}){
  const carga=(nome,d)=>registry.filter(c=>(d==="fiscal"?c.respFiscal:c.respPessoal)===nome).length;
  return <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:11,overflow:"hidden",display:"flex",flexDirection:"column"}}><div style={{flex:1,overflow:"auto"}}><table style={tbl}><thead style={sticky}><tr style={trh}>{["Funcionário","Cargo","Departamento","Usuário","Acesso","Carga","Status",""].map(h=><th key={h} style={th}>{h}</th>)}</tr></thead>
    <tbody>{employees.map(e=>{const acc=e.isAdmin?"Administrador":[e.canCentral?"Cadastro":null,e.deptEdit?("Edita "+DEPT_LABEL[e.deptEdit]):null,e.onlyAssigned?"(só atribuídas)":null,e.canAssign?"atribui":null].filter(Boolean).join(" · ")||"Visualização";
      return <tr key={e.id} className="rowh" style={trb}>
      <td style={td}><div style={{fontWeight:700}}>{e.nome}</div><div style={{fontSize:11,color:C.muted}}>{e.email||"—"}</div></td>
      <td style={{...td,color:C.body}}>{e.cargo||"—"}</td>
      <td style={td}>{e.dept==="admin"?<Pill bg={C.navySoft} fg={C.navy} br="#dbe2f0">Administração</Pill>:<Pill bg={C.bg} fg={C.body} br={C.line}>{DEPT_LABEL[e.dept]||"—"}</Pill>}</td>
      <td style={{...td,color:C.body}} className="tnum">{e.user}</td>
      <td style={{...td,color:C.body,fontSize:11.5}}>{acc}</td>
      <td style={{...td,color:C.muted,fontSize:12}} className="tnum">{e.dept==="fiscal"?carga(e.nome,"fiscal")+" emp.":e.dept==="pessoal"?carga(e.nome,"pessoal")+" emp.":"—"}</td>
      <td style={td}><StatusPill s={e.ativo?"Ativo":"Inativo"} /></td>
      <td style={{...td,textAlign:"right"}}><button onClick={()=>onEdit(e)} style={iconBtn(C.muted)}><Pencil size={14} /></button></td>
    </tr>;})}</tbody></table></div></div>;
}

function Historico({log}){
  return <div style={{flex:1,minHeight:0,background:C.card,border:`1px solid ${C.line}`,borderRadius:11,overflow:"hidden",display:"flex",flexDirection:"column"}}><div style={{padding:"12px 18px",borderBottom:`1px solid ${C.line}`,fontSize:12.5,color:C.muted,flexShrink:0}}>Registro de alterações (mais recentes primeiro) — controle de segurança.</div><div style={{flex:1,overflow:"auto"}}><table style={tbl}><thead style={sticky}><tr style={trh}><th style={th}>Data / hora</th><th style={th}>Usuário</th><th style={th}>Ação</th></tr></thead>
    <tbody>{[...log].reverse().map((e,i)=><tr key={i} style={trb}><td style={{...td,color:C.body}} className="tnum">{fmtDT(e.ts)}</td><td style={{...td,fontWeight:700}}>{e.user}</td><td style={{...td,color:C.body}}>{e.action}</td></tr>)}
    {log.length===0&&<tr><td colSpan={3} style={{...td,textAlign:"center",color:C.muted,padding:30}}>Nenhuma alteração registrada ainda.</td></tr>}</tbody></table></div></div>;
}

function EmpModal({emp,employees,onClose,onSave,onDelete}){
  const isNew=!emp.id;
  const [v,setV]=useState(()=>({id:emp.id,nome:emp.nome||"",cpf:emp.cpf||"",email:emp.email||"",cargo:emp.cargo||"",dept:emp.dept&&emp.dept!=="admin"?emp.dept:"fiscal",user:emp.user||"",pwd:emp.pwd||"",isAdmin:!!emp.isAdmin,canCentral:!!emp.canCentral,canAssign:!!emp.canAssign,onlyAssigned:emp.onlyAssigned!==false?!!emp.onlyAssigned:false,view:emp.view?emp.view.slice():VIEW_ALL.slice(),ativo:emp.ativo!==false}));
  const set=(k,val)=>setV(o=>({...o,[k]:val}));
  const toggleView=(d)=>setV(o=>({...o,view:o.view.includes(d)?o.view.filter(x=>x!==d):[...o.view,d]}));
  const dup=employees.some(e=>e.user===v.user.trim().toLowerCase()&&e.id!==v.id);
  const ok=v.nome.trim()&&v.user.trim()&&v.pwd.trim()&&!dup;
  const save=()=>{ if(!ok)return; onSave({...v,user:v.user.trim().toLowerCase(),nome:v.nome.trim(),dept:v.isAdmin?"admin":v.dept,deptEdit:v.isAdmin?"":v.dept,view:v.isAdmin?VIEW_ALL.slice():v.view}); };
  const inputS={width:"100%",padding:"9px 11px",borderRadius:8,border:`1px solid ${C.line}`,background:"#fff",fontSize:13,color:C.ink,marginTop:5};
  return <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(12,22,64,.45)",display:"grid",placeItems:"center",zIndex:30}}>
    <div onClick={e=>e.stopPropagation()} style={{width:580,maxWidth:"95%",maxHeight:"92%",overflow:"auto",background:C.card,borderRadius:14,padding:"22px 24px",animation:"pop .2s ease"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><h2 style={{margin:0,fontSize:19,fontWeight:800,color:C.ink}}>{isNew?"Novo funcionário":"Editar funcionário"}</h2><button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={20} /></button></div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px 14px",marginTop:14}}>
        <div style={{gridColumn:"1 / span 2"}}><label style={fl}>Nome completo *</label><input value={v.nome} onChange={e=>set("nome",e.target.value)} style={inputS} placeholder="Nome e sobrenome" /></div>
        <div><label style={fl}>CPF</label><input value={v.cpf} onChange={e=>set("cpf",e.target.value)} style={inputS} placeholder="000.000.000-00" /></div>
        <div><label style={fl}>E-mail</label><input value={v.email} onChange={e=>set("email",e.target.value)} style={inputS} placeholder="nome@contabilizar.com" /></div>
        <div><label style={fl}>Cargo</label><input value={v.cargo} onChange={e=>set("cargo",e.target.value)} style={inputS} placeholder="Ex.: Analista Fiscal" /></div>
        <div><label style={fl}>Departamento</label><select value={v.dept} disabled={v.isAdmin} onChange={e=>set("dept",e.target.value)} style={{...inputS,cursor:v.isAdmin?"not-allowed":"pointer"}}>{["fiscal","pessoal","contabil","paralegal","financeiro","recepcao","rh"].map(d=><option key={d} value={d}>{DEPT_LABEL[d]}</option>)}</select></div>
      </div>
      <div style={{height:1,background:C.line,margin:"16px 0 4px"}} />
      <div style={{fontSize:11.5,fontWeight:800,color:C.navy,letterSpacing:.4,textTransform:"uppercase",margin:"8px 0"}}><KeyRound size={13} style={{verticalAlign:-2,marginRight:5}} />Credenciais de acesso</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"10px 14px"}}>
        <div><label style={fl}>Usuário *</label><input value={v.user} onChange={e=>set("user",e.target.value)} style={{...inputS,borderColor:dup?C.red:C.line}} placeholder="usuario.login" />{dup&&<div style={{fontSize:11,color:C.red,marginTop:3}}>Usuário já existe.</div>}</div>
        <div><label style={fl}>Senha *</label><input value={v.pwd} onChange={e=>set("pwd",e.target.value)} style={inputS} placeholder="senha" /></div>
      </div>
      <div style={{height:1,background:C.line,margin:"16px 0 4px"}} />
      <div style={{fontSize:11.5,fontWeight:800,color:C.navy,letterSpacing:.4,textTransform:"uppercase",margin:"8px 0"}}><ShieldCheck size={13} style={{verticalAlign:-2,marginRight:5}} />Permissões de acesso</div>
      <label style={chk}><input type="checkbox" checked={v.isAdmin} onChange={e=>set("isAdmin",e.target.checked)} /> <b>Administrador</b> — acesso total e gestão da equipe</label>
      <label style={chk}><input type="checkbox" checked={v.ativo} onChange={e=>set("ativo",e.target.checked)} /> Funcionário ativo (pode acessar o sistema)</label>
      {!v.isAdmin&&<><label style={chk}><input type="checkbox" checked={v.canCentral} onChange={e=>set("canCentral",e.target.checked)} /> Pode incluir/excluir empresas e mudar situação (Cadastro Central)</label>
      <label style={chk}><input type="checkbox" checked={v.canAssign} onChange={e=>set("canAssign",e.target.checked)} /> Pode <b>atribuir o responsável</b> das empresas do seu departamento</label>
      <label style={chk}><input type="checkbox" checked={v.onlyAssigned} onChange={e=>set("onlyAssigned",e.target.checked)} /> Edita <b>apenas</b> as empresas atribuídas a ele (demais só visualiza)</label>
      <div style={{fontSize:11.5,fontWeight:700,color:C.muted,margin:"12px 0 6px"}}>Departamentos que pode VISUALIZAR (edita só o seu: {DEPT_LABEL[v.dept]})</div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:"4px 10px"}}>{VIEW_ALL.map(d=><label key={d} style={{...chk,margin:0}}><input type="checkbox" checked={v.view.includes(d)} onChange={()=>toggleView(d)} /> {DEPT_LABEL[d]}</label>)}</div></>}
      <div style={{display:"flex",gap:10,marginTop:20,alignItems:"center"}}>
        {!isNew&&<button onClick={()=>onDelete(v.id,v.nome)} style={{padding:"10px 14px",borderRadius:9,border:`1px solid ${C.redSoft}`,background:C.redSoft,color:C.red,fontWeight:700,fontSize:13,cursor:"pointer"}}>Remover</button>}
        <div style={{flex:1}} /><button onClick={onClose} style={{padding:"10px 18px",borderRadius:9,border:`1px solid ${C.line}`,background:C.bg,color:C.body,fontWeight:700,fontSize:13.5,cursor:"pointer"}}>Cancelar</button>
        <button onClick={save} disabled={!ok} style={{padding:"10px 20px",borderRadius:9,border:"none",background:ok?C.navy:"#c9cdd6",color:"#fff",fontWeight:700,fontSize:13.5,cursor:ok?"pointer":"not-allowed"}}>Salvar</button>
      </div>
    </div></div>;
}
const chk={display:"flex",alignItems:"center",gap:8,fontSize:12.8,color:C.body,margin:"7px 0",cursor:"pointer"};

function AddModal({onClose,onSave,nextCode}){
  const [v,setV]=useState({razao:"",cnpj:"",regime:"SIMPLES NACIONAL",municipio:"",segmento:"",tipoFolha:"FOLHA",situacao:"Ativo",dataSituacao:"",codigo:String(nextCode)});
  const set=(k,val)=>setV({...v,[k]:val}); const ok=v.razao.trim()&&v.cnpj.trim();
  const field=(label,key,ph)=>(<div><label style={{...lbl,marginTop:12}}>{label}</label><input value={v[key]} onChange={e=>set(key,e.target.value)} style={inp} placeholder={ph} /></div>);
  return <div onClick={onClose} style={{position:"absolute",inset:0,background:"rgba(12,22,64,.45)",display:"grid",placeItems:"center",zIndex:20}}>
    <div onClick={e=>e.stopPropagation()} style={{width:470,background:C.card,borderRadius:14,padding:"24px 26px",animation:"pop .2s ease",maxHeight:"92%",overflow:"auto"}}>
      <div style={{display:"flex",justifyContent:"space-between",alignItems:"center"}}><h2 style={{margin:0,fontSize:19,fontWeight:800,color:C.ink}}>Nova empresa</h2><button onClick={onClose} style={{background:"none",border:"none",cursor:"pointer",color:C.muted}}><X size={20} /></button></div>
      <p style={{fontSize:12.5,color:C.muted,marginTop:4}}>Cadastro único. Os responsáveis são definidos em cada departamento.</p>
      <div style={{display:"flex",gap:12}}><div style={{flex:"0 0 110px"}}>{field("Código","codigo","000")}</div><div style={{flex:1}}>{field("Razão social *","razao","NOVA EMPRESA LTDA")}</div></div>
      {field("CNPJ *","cnpj","00.000.000/0001-00")}
      <div style={{display:"flex",gap:12}}><div style={{flex:1}}><label style={{...lbl,marginTop:12}}>Regime</label><select value={v.regime} onChange={e=>set("regime",e.target.value)} style={inp}>{["SIMPLES NACIONAL","LUCRO PRESUMIDO","LUCRO REAL","PRODUTOR RURAL","DOMÉSTICA","ASSOCIAÇÃO PRIVADA","MEI"].map(o=><option key={o}>{o}</option>)}</select></div><div style={{flex:1}}>{field("Município","municipio","Cidade")}</div></div>
      <div style={{display:"flex",gap:12}}><div style={{flex:1}}><label style={{...lbl,marginTop:12}}>Tipo de folha</label><select value={v.tipoFolha} onChange={e=>set("tipoFolha",e.target.value)} style={inp}>{["FOLHA","PRÓ-LABORE","SEM FOLHA"].map(o=><option key={o}>{o}</option>)}</select></div><div style={{flex:1}}><label style={{...lbl,marginTop:12}}>Situação</label><select value={v.situacao} onChange={e=>set("situacao",e.target.value)} style={inp}>{["Ativo","Inativo","Bloqueada"].map(o=><option key={o}>{o}</option>)}</select></div></div>
      <div style={{display:"flex",gap:10,marginTop:22}}><button onClick={onClose} style={{flex:1,padding:11,borderRadius:9,border:`1px solid ${C.line}`,background:C.bg,color:C.body,fontWeight:700,fontSize:13.5,cursor:"pointer"}}>Cancelar</button><button onClick={()=>ok&&onSave(v)} disabled={!ok} style={{flex:1,padding:11,borderRadius:9,border:"none",background:ok?C.navy:"#c9cdd6",color:"#fff",fontWeight:700,fontSize:13.5,cursor:ok?"pointer":"not-allowed"}}>Incluir empresa</button></div>
    </div></div>;
}

function Login({employees,onLogin}){
  const [u,setU]=useState("");const [p,setP]=useState("");const [err,setErr]=useState("");
  const go=()=>{const e=employees.find(x=>x.user===u.trim().toLowerCase()&&x.pwd===p&&x.ativo);if(e)onLogin(e);else setErr("Usuário/senha inválidos ou acesso inativo.");};
  return <div style={{display:"flex",height:"100vh",overflow:"hidden"}}><style>{FONTS}</style>
    <div style={{flex:1.05,background:C.navyDeep,color:"#fff",padding:"52px 46px",display:"flex",flexDirection:"column",justifyContent:"space-between",position:"relative",overflow:"hidden"}}>
      <div style={{position:"absolute",right:-120,top:-60,width:360,height:360,borderRadius:"50%",background:"radial-gradient(circle, rgba(144,152,152,.18), transparent 70%)"}} />
      <img src={LOGO_SYM} alt="" style={{width:46,height:46,objectFit:"contain",filter:"brightness(0) invert(1)",opacity:.96,position:"relative"}} />
      <div style={{position:"relative"}}><h2 style={{fontSize:32,fontWeight:800,lineHeight:1.15,margin:0,maxWidth:380,letterSpacing:-0.5}}>Controle por competência, em um só lugar.</h2><p style={{color:"#b9c0d4",fontSize:14,marginTop:16,maxWidth:380,lineHeight:1.55}}>Dashboard por departamento, progresso real e histórico de alterações.</p></div>
      <div style={{position:"relative",display:"flex",gap:24,color:"#b9c0d4",fontSize:12.5}}><span><b style={{color:"#fff"}}>317</b> empresas</span><span><b style={{color:"#fff"}}>9</b> funcionários</span><span><b style={{color:"#fff"}}>7</b> departamentos</span></div>
    </div>
    <div style={{flex:1,background:C.card,padding:"44px 50px",display:"flex",flexDirection:"column",justifyContent:"center"}}>
      <img src={LOGO_WORD} alt="CONTABILIZARe" style={{height:30,alignSelf:"flex-start",marginBottom:22}} />
      <h1 style={{fontSize:24,fontWeight:800,margin:0,color:C.ink,letterSpacing:-0.3}}>Acessar o Hub</h1><p style={{color:C.muted,fontSize:13.5,marginTop:5}}>Entre com seu usuário do escritório.</p>
      <label style={lbl}>USUÁRIO</label><input value={u} onChange={e=>{setU(e.target.value);setErr("");}} onKeyDown={e=>e.key==="Enter"&&go()} style={inp} placeholder="seu.usuario" />
      <label style={lbl}>SENHA</label><div style={{position:"relative"}}><Lock size={15} color={C.muted} style={{position:"absolute",left:12,top:13}} /><input type="password" value={p} onChange={e=>{setP(e.target.value);setErr("");}} onKeyDown={e=>e.key==="Enter"&&go()} style={{...inp,paddingLeft:34}} placeholder="••••••" /></div>
      {err&&<div style={{color:C.red,fontSize:12.5,marginTop:10}}>{err}</div>}
      <button onClick={go} style={{marginTop:20,padding:12,borderRadius:9,border:"none",background:C.navy,color:"#fff",fontSize:14.5,fontWeight:700,cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",gap:8}}>Entrar <ArrowRight size={16} /></button>
      <div style={{marginTop:18,padding:13,borderRadius:9,background:C.bg,border:`1px dashed ${C.line}`,fontSize:12,color:C.muted,lineHeight:1.7}}><b style={{color:C.ink}}>Acessos</b> (senha <code>123</code>):<br /><code>admin</code> · <code>financeiro</code> · <code>raissa</code> (gestora fiscal) · <code>yesa</code> (gestora pessoal) · <code>suelen</code>, <code>neirieli</code> (fiscal) · <code>hudson</code>, <code>leticia</code> (pessoal)</div>
    </div></div>;
}
const lbl={fontSize:11.5,fontWeight:700,color:C.muted,marginTop:16,display:"block",letterSpacing:.5};
const inp={width:"100%",padding:"11px 12px",borderRadius:9,border:`1px solid ${C.line}`,background:C.bg,fontSize:14,color:C.ink,marginTop:6};
const fl={fontSize:11,fontWeight:700,color:C.muted,letterSpacing:.3,display:"block",marginBottom:5};
const secT={fontSize:11.5,fontWeight:800,color:C.navy,letterSpacing:.5,textTransform:"uppercase",margin:"6px 0 10px"};
