const trb={borderTop:`1px solid ${C.line}`};
const th={padding:"10px 14px",fontSize:11,fontWeight:700,letterSpacing:.4,textTransform:"uppercase",background:C.bg};
const td={padding:"10px 14px",verticalAlign:"middle",color:C.ink};
const cellInp={width:"100%",padding:"6px 8px",borderRadius:7,border:`1px solid ${C.navy}`,background:"#fff",fontSize:12.5,color:C.ink};
